SELECT *
FROM device_operation_log
WHERE device_code = #{deviceCode}
  AND operation_time >=
      #{startTime,typeHandler=cn.itzixiao.interview.provider.config.handler.CustomLocalDateTimeTypeHandler}
  AND operation_time <=
      #{endTime,typeHandler=cn.itzixiao.interview.provider.config.handler.CustomLocalDateTimeTypeHandler}
ORDER BY operation_time ASC
